import React, { useState, useEffect, useRef } from 'react';
import { 
  Search,
  Filter,
  Users,
  UserPlus,
  ChevronDown,
  Check
} from 'lucide-react';

const ActionBar = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortDropdownOpen, setSortDropdownOpen] = useState(false);
  const [selectedSort, setSelectedSort] = useState('Recent Activity');
  const sortDropdownRef = useRef(null);

  // Opções de ordenação
  const sortOptions = [
    'Recent Activity',
    'Status',
    'Name (A–Z)',
    'Name (Z–A)',
    'Role',
    'Date Created (Newest)',
    'Date Created (Oldest)'
  ];

  // Fechar dropdown quando clicar fora
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (sortDropdownRef.current && !sortDropdownRef.current.contains(event.target)) {
        setSortDropdownOpen(false);
      }
    };

    if (sortDropdownOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [sortDropdownOpen]);

  const handleSortClick = () => {
    setSortDropdownOpen(!sortDropdownOpen);
  };

  const handleSortSelect = (option) => {
    setSelectedSort(option);
    setSortDropdownOpen(false);
    console.log(`Sort selected: ${option}`);
  };

  return (
    <div className="w-fit bg-neutral-800 rounded-lg h-20 p-4 flex items-center space-x-3">
      {/* Search Input */}
      <div className="relative">
        <input
          type="text"
          placeholder="Search..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-48 bg-neutral-700 border border-neutral-600 rounded-lg px-4 py-2 pl-10 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent text-sm"
        />
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-neutral-400" />
      </div>

      {/* Sort Button with Dropdown */}
      <div className="relative" ref={sortDropdownRef}>
        <button 
          onClick={handleSortClick}
          className="flex items-center space-x-2 px-4 py-2 bg-neutral-700 hover:bg-neutral-600 border border-neutral-600 rounded-lg transition-colors"
        >
          <Filter className="h-4 w-4 text-neutral-300" />
          <span className="text-neutral-300 text-sm font-medium">Sort</span>
          <ChevronDown className={`h-4 w-4 text-neutral-300 transition-transform ${sortDropdownOpen ? 'rotate-180' : ''}`} />
        </button>

        {/* Dropdown Menu */}
        {sortDropdownOpen && (
          <div className="absolute top-full left-0 mt-1 bg-neutral-900 border border-neutral-700 rounded-lg shadow-2xl z-50 min-w-[200px]">
            <div className="py-1">
              {sortOptions.map((option, index) => (
                <button
                  key={index}
                  onClick={() => handleSortSelect(option)}
                  className={`w-full text-left px-3 py-2 text-sm transition-colors flex items-center justify-between ${
                    selectedSort === option 
                      ? 'bg-neutral-700 text-white' 
                      : 'text-neutral-300 hover:bg-neutral-800 hover:text-white'
                  }`}
                >
                  <span>{option}</span>
                  {selectedSort === option && (
                    <Check className="h-4 w-4 text-white" />
                  )}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Create Group Button */}
      <button className="flex items-center space-x-2 px-4 py-2 bg-neutral-700 hover:bg-neutral-600 border border-neutral-600 rounded-lg transition-colors">
        <Users className="h-4 w-4 text-neutral-300" />
        <span className="text-neutral-300 text-sm font-medium">Create group</span>
      </button>

      {/* Invite Button */}
      <button className="flex items-center space-x-2 px-4 py-2 bg-white hover:bg-gray-100 rounded-lg transition-colors">
        <UserPlus className="h-4 w-4 text-black" />
        <span className="text-black text-sm font-medium">Invite</span>
      </button>
    </div>
  );
};

export default ActionBar;
